709 static Value *simplifyNeonTbl1(const IntrinsicInst &II,
710                                InstCombiner::BuilderTy &Builder) {
711   // Bail out if the mask is not a constant.
712   auto *C = dyn_cast<Constant>(II.getArgOperand(1));
713   if (!C)
