1316   template <typename OpTy> bool match(OpTy *V) {
1317     if (auto *I = dyn_cast<Instruction>(V))
1318       return this->isOpType(I->getOpcode()) && L.match(I->getOperand(0)) &&
1319              R.match(I->getOperand(1));
1320     return false;
1321   }
1322 };
